const OuOSpriteAsset* findOuOSprite(uint16_t handle) {
    for (uint16_t i = 0; i < OUO_SPRITE_COUNT; ++i) {
        uint16_t current = pgm_read_word(&OUO_SPRITES[i].handle);
        if (current == handle) {
            return &OUO_SPRITES[i];
        }
    }
    return nullptr;
}
